use std::marker::PhantomData;

// State types (zero-sized, exist only for the type system)
struct Draft;
struct Review;
struct Published;

struct Article<State> {
    title: String,
    body: String,
    _state: PhantomData<State>,
}

// Only Draft articles can be edited
impl Article<Draft> {
    fn new(title: String) -> Self {
        Article {
            title,
            body: String::new(),
            _state: PhantomData,
        }
    }

    fn set_body(mut self, body: String) -> Self {
        self.body = body;
        self
    }

    fn submit_for_review(self) -> Article<Review> {
        println!("'{}' submitted for review", self.title);
        Article {
            title: self.title,
            body: self.body,
            _state: PhantomData,
        }
    }
}

// Only Review articles can be approved or rejected
impl Article<Review> {
    fn approve(self) -> Article<Published> {
        println!("'{}' approved!", self.title);
        Article {
            title: self.title,
            body: self.body,
            _state: PhantomData,
        }
    }

    fn reject(self) -> Article<Draft> {
        println!("'{}' rejected, back to draft", self.title);
        Article {
            title: self.title,
            body: self.body,
            _state: PhantomData,
        }
    }
}

// Only Published articles can be viewed
impl Article<Published> {
    fn view(&self) -> String {
        format!("# {}\n\n{}", self.title, self.body)
    }
}

fn main() {
    let article = Article::<Draft>::new("Rust Typestate".into())
        .set_body("Typestate is a powerful pattern...".into())
        .submit_for_review()
        .approve();

    println!("{}", article.view());

    // These would NOT compile:
    // article.set_body("...".into());  // Can't edit a Published article
    // article.approve();               // Can't approve a Published article
}
